-- Three pattern-match queries. Fill in the LIKE expression:

-- Names starting with 'A':
SELECT * FROM users WHERE name LIKE '___';

-- Emails ending with '@gmail.com':
SELECT * FROM users WHERE email LIKE '___';

-- Names with exactly one character before 'lice' (matches 'Alice', NOT 'Aslice'):
SELECT * FROM users WHERE name LIKE '___';

cards.answer:
```sql
-- INSERT one row:
INSERT INTO users (email, age) VALUES ('a@x.com', 30);

-- INSERT multiple rows in one statement (more efficient than N separate INSERTs):
INSERT INTO users (email, age) VALUES
  ('a@x.com', 30),
  ('b@y.com', 25),
  ('c@z.com', 40);

-- UPDATE specific rows:
UPDATE users SET age = 31 WHERE name = 'Alice';

-- DELETE specific rows:
DELETE FROM users WHERE id = 5;

-- Postgres: see the affected rows in the response
INSERT INTO users (email) VALUES ('a@x.com') RETURNING id, created_at;
UPDATE users SET age = 31 WHERE id = 5 RETURNING *;
DELETE FROM users WHERE id = 5 RETURNING name, email;
```
